def predict_next_frame(frame, action, xy=None):
    next_frame = [row[:] for row in frame]

    if action.startswith("ACTION6") and xy is not None:
        x, y = xy
        row = y
        col = x

        if 0 <= row < 64 and 0 <= col < 64:
            # Check if the cell is 7 and change it to 4
            if next_frame[row][col] == 7:
                next_frame[row][col] = 4
            # Check neighboring cells (up, down, left, right)
            # Check up
            if row > 0 and next_frame[row - 1][col] == 7:
                next_frame[row - 1][col] = 4
            # Check down
            if row < 63 and next_frame[row + 1][col] == 7:
                next_frame[row + 1][col] = 4
            # Check left
            if col > 0 and next_frame[row][col - 1] == 7:
                next_frame[row][col - 1] = 4
            # Check right
            if col < 63 and next_frame[row][col + 1] == 7:
                next_frame[row][col + 1] = 4

    return next_frame

